+import { GainsightIdDirective } from '../../directives/gainsightId.directive';
+import { ComponentFixture, TestBed } from '@angular/core/testing';
+import { FormsModule } from '@angular/forms';
+import { MemoEditorComponent } from './memo-editor.component';
+import { ElementRef } from '@angular/core';
+import { PageService } from 'shared/services/PageService';
+import { ComponentSettingsService } from 'shared/services/ComponentSettingsService';
+import { CurrentContextService } from 'shared/services/CurrentContextService';
+
+describe('MemoEditorComponent', () => {
+    let component: MemoEditorComponent;
+    let fixture: ComponentFixture<MemoEditorComponent>;
+
+    beforeEach(async () => {
+        await TestBed.configureTestingModule({
+            imports: [FormsModule, MemoEditorComponent, GainsightIdDirective],
+            providers: [CurrentContextService, PageService, ComponentSettingsService],
+        }).compileComponents();
+    });
+
+    beforeEach(() => {
+        fixture = TestBed.createComponent(MemoEditorComponent);
+        component = fixture.componentInstance;
+        fixture.detectChanges();
+    });
+
+    it('should create the component', () => {
+        expect(component).toBeTruthy();
+    });
+
+    it('should initialize with default values', () => {
+        expect(component.height()).toBe('100%');
+        expect(component.maxLength()).toBe(2147483647);
+        expect(component.rows()).toBe(3);
+        expect(component.heightByContainer()).toBe(false);
+    });
+
+    it('should set maxLength from _fieldInfo.MaximumLength during initialization', () => {
+        component['_fieldInfo'] = { MaximumLength: 500, IsUDF: false, ForCompactForm: false } as any;
+        component['initialize']();
+        expect(component.maxLength()).toBe(500);
+    });
+
+    it('should set height and width for UDF fields during initialization', () => {
+        component['_fieldInfo'] = { MaximumLength: 500, IsUDF: true, ForCompactForm: false } as any;
+        component['initialize']();
+        expect(component.height()).toBe('60px');
+        expect(component.width()).toBe('300px');
+    });
+
+    it('should focus on the textbox when focus() is called', () => {
+        const mockElementRef = { nativeElement: { focus: jasmine.createSpy('focus') } } as ElementRef;
+        component['_textBox'] = mockElementRef;
+        component.focus();
+        expect(mockElementRef.nativeElement.focus).toHaveBeenCalled();
+    });
+
+    it('should call detectChanges and return true in endEditing()', () => {
+        const detectChangesSpy = spyOn(component['_cd'], 'detectChanges');
+        const result = component.endEditing();
+        expect(detectChangesSpy).toHaveBeenCalled();
+        expect(result).toBeTrue();
+    });
+});
